package com.google.gson.stream;
import com.google.gson.internal.JsonReaderInternalAccess;
import com.google.gson.internal.bind.JsonTreeReader;
import java.io.Closeable;
import java.io.EOFException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonReaderTest {
  private JsonReader jsonReader;

  @BeforeEach
  public void setUp() {
    // Create a JsonReader with dummy Reader (null) since we will manipulate buffer and pos directly
    jsonReader = new JsonReader(null);
  }

  private void setField(String fieldName, Object value) throws Exception {
    var field = JsonReader.class.getDeclaredField(fieldName);
    field.setAccessible(true);
    field.set(jsonReader, value);
  }

  private Object getField(String fieldName) throws Exception {
    var field = JsonReader.class.getDeclaredField(fieldName);
    field.setAccessible(true);
    return field.get(jsonReader);
  }

  private void invokeNextNonWhitespace(boolean throwOnEof) throws Exception {
    Method m = JsonReader.class.getDeclaredMethod("nextNonWhitespace", boolean.class);
    m.setAccessible(true);
    m.invoke(jsonReader, throwOnEof);
  }

  private boolean invokeFillBuffer(int minimum) throws Exception {
    Method m = JsonReader.class.getDeclaredMethod("fillBuffer", int.class);
    m.setAccessible(true);
    return (boolean) m.invoke(jsonReader, minimum);
  }

  private void invokeConsumeNonExecutePrefix() throws Exception {
    Method m = JsonReader.class.getDeclaredMethod("consumeNonExecutePrefix");
    m.setAccessible(true);
    m.invoke(jsonReader);
  }

  @Test
  public void testConsumeNonExecutePrefix_posDecrementedAfterNextNonWhitespace() throws Exception {
    // Setup: pos = 1, limit = 10, buffer has irrelevant data
    setField("pos", 1);
    setField("limit", 10);
    char[] buffer = new char[1024];
    buffer[0] = ' ';
    buffer[1] = 'a';
    setField("buffer", buffer);

    // Spy on jsonReader to intercept nextNonWhitespace and fillBuffer calls
    JsonReader spyReader = spy(jsonReader);
    doAnswer(invocation -> {
      // Simulate nextNonWhitespace advancing pos from 1 to 2
      setField("pos", 2);
      return null;
    }).when(spyReader).getClass().getDeclaredMethod("nextNonWhitespace", boolean.class).invoke(spyReader, true);

    // We cannot mock private method easily, so instead invoke original method and set pos manually
    // Instead, just test pos decrement after nextNonWhitespace call
    invokeNextNonWhitespace(true);
    int posAfterNextNonWhitespace = (int) getField("pos");
    // pos should be decremented by 1 after nextNonWhitespace
    setField("pos", posAfterNextNonWhitespace);
    invokeConsumeNonExecutePrefix();
    int posAfterConsume = (int) getField("pos");
    assertEquals(posAfterNextNonWhitespace - 1, posAfterConsume);
  }

  @Test
  public void testConsumeNonExecutePrefix_returnsIfBufferNotFilled() throws Exception {
    // pos + 5 > limit and fillBuffer returns false -> method returns early
    setField("pos", 6);
    setField("limit", 10);
    char[] buffer = new char[1024];
    setField("buffer", buffer);

    // Spy and mock fillBuffer to return false
    JsonReader spyReader = spy(jsonReader);
    Method fillBufferMethod = JsonReader.class.getDeclaredMethod("fillBuffer", int.class);
    fillBufferMethod.setAccessible(true);
    doReturn(false).when(spyReader).fillBuffer(5);

    // Because fillBuffer is private, we cannot mock it directly on spyReader easily.
    // Instead, forcibly set limit so pos + 5 > limit and fillBuffer returns false.
    setField("limit", 10);
    setField("pos", 6);

    // Use reflection to invoke consumeNonExecutePrefix on original jsonReader
    // It should return early and pos should remain unchanged after decrement + early return
    setField("pos", 6);
    invokeConsumeNonExecutePrefix();
    int posAfter = (int) getField("pos");
    // pos is decremented by 1 after nextNonWhitespace, then early return, so pos = 5
    assertEquals(5, posAfter);
  }

  @Test
  public void testConsumeNonExecutePrefix_returnsIfBufferDoesNotMatchSecurityToken() throws Exception {
    // Setup buffer with chars not matching the security token
    char[] buffer = new char[1024];
    buffer[0] = ')';
    buffer[1] = ']';
    buffer[2] = '}'; 
    buffer[3] = '\''; 
    buffer[4] = 'x'; // last char different from '\n'
    setField("buffer", buffer);
    setField("pos", 0);
    setField("limit", 10);

    // FillBuffer returns true (simulate buffer filled sufficiently)
    // We cannot mock fillBuffer easily, but limit is enough here
    invokeConsumeNonExecutePrefix();
    // pos should be decremented by 1 after nextNonWhitespace (pos=0->pos=-1), then early return
    int posAfter = (int) getField("pos");
    assertEquals(-1, posAfter);
  }

  @Test
  public void testConsumeNonExecutePrefix_consumesSecurityToken() throws Exception {
    // Setup buffer with exact security token ") ] } ' \n"
    char[] buffer = new char[1024];
    buffer[0] = ')';
    buffer[1] = ']';
    buffer[2] = '}';
    buffer[3] = '\'';
    buffer[4] = '\n';
    setField("buffer", buffer);
    setField("pos", 0);
    setField("limit", 10);

    // Invoke consumeNonExecutePrefix
    invokeConsumeNonExecutePrefix();

    // pos should be decremented by 1 after nextNonWhitespace (pos=0->pos=-1)
    // then pos +=5 for consuming security token => pos = 4
    int posAfter = (int) getField("pos");
    assertEquals(4, posAfter);
  }
}
